  'budget.addSub': { en: 'Add sub-category', am: 'ንዑስ ምድብ ጨምር', om: 'Ramaddii xiqqaa dabali', sw: 'Ongeza kategoria ndogo' },
  'budget.footer': { en: 'Sub-category budgets add up into each main category. The bar shows your allocation vs the 50/30/20 target (marker line).', am: 'የንዑስ ምድብ በጀቶች ወደ እያንዳንዱ ዋና ምድብ ይደመራሉ። አሞሌው ምደባዎን ከ50/30/20 ግብ ጋር ያሳያል።', om: 'Baajanni ramaddii xiqqaa ramaddii guddaa hundatti ida\'ama. Saaphaphuun ramaddii kee galma 50/30/20 waliin agarsiisa.', sw: 'Bajeti za kategoria ndogo zinajumlika kwa kila kategoria kuu. Mwambaa unaonyesha mgawanyo wako dhidi ya lengo la 50/30/20.' },

