  'analytics.onPace': { en: 'On pace', am: 'በትክክለኛ ፍጥነት', om: 'Saffisa sirrii', sw: 'Kwa kasi sahihi' },
  'analytics.overPace': { en: 'Over pace', am: 'ከፍጥነት በላይ', om: 'Saffisa ol', sw: 'Zaidi ya kasi' },
