  'analytics.whereItGoes': { en: 'Where it goes', am: 'የት እንደሚሄድ', om: 'Eessa akka dhaqu', sw: 'Inakoenda' },
  'analytics.topSpending': { en: 'Top spending', am: 'ከፍተኛ ወጪ', om: 'Baasii ol\'aanaa', sw: 'Matumizi makubwa' },
  'analytics.allocationVsCap': { en: 'Allocation vs cap', am: 'ምደባ ከጣሪያ ጋር', om: 'Ramaddii vs daangaa', sw: 'Mgawanyo dhidi ya kikomo' },
