  'analytics.perDay': { en: '/day · {days} days left', am: '/ቀን · {days} ቀናት ቀርተዋል', om: '/guyyaa · guyyoota {days} hafan', sw: '/siku · siku {days} zimebaki' },
  'analytics.monthComplete': { en: 'Month complete.', am: 'ወሩ ተጠናቋል።', om: 'Ji\'i xumurame.', sw: 'Mwezi umekamilika.' },
